def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0
        temp_ratio = ratio
        for j in range(5):
            if temp_ratio < 0.05:
                score += (0.05 - temp_ratio) ** 3
            elif temp_ratio < 0.2:
                score += (0.2 - temp_ratio) ** 2
            elif temp_ratio < 0.7:
                score += np.sin(temp_ratio * np.pi)
            else:
                score += np.log1p(temp_ratio)
            temp_ratio = temp_ratio ** 0.6
        if abs(ratio - 1) < 0.1:
            score *= 0.5
        elif ratio > 1:
            score *= 2
        if capacity % 2 == 0:
            score -= 0.1
        else:
            score += 0.1
        priorities[i] = max(score, 0)
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if not np.isfinite(priorities[i]):
                priorities[i] = max_priority + 2
    else:
        priorities[:] = 1e6
    for _ in range(2):
        for i in range(len(priorities)):
            for j in range(len(priorities)):
                if i != j and priorities[i] > priorities[j]:
                    priorities[i] -= 0.01
    return priorities
